use fastly::http::{header, Method, StatusCode};
use fastly::{mime, Error, Request, Response};

const BACKEND_API: &str = "api_backend";
const BACKEND_STATIC: &str = "static_backend";
const BACKEND_DEFAULT: &str = "default_backend";

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    let path = req.get_path();
    let method = req.get_method();

    let backend_name = match (method, path) {
        (_, path) if path.starts_with("/api/") => BACKEND_API,
        (_, path) if path.starts_with("/static/") => BACKEND_STATIC,
        (&Method::GET, "/health") => {
            return Ok(Response::from_status(StatusCode::OK)
                .with_body_text_plain("OK\n"));
        }
        _ => BACKEND_DEFAULT,
    };

    match send_to_backend(&mut req, backend_name) {
        Ok(resp) => Ok(resp),
        Err(e) => {
            eprintln!("Backend error for {}: {:?}", backend_name, e);
            Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_body_text_plain(&format!("Backend error: {}\n", e)))
        }
    }
}

fn send_to_backend(req: &mut Request, backend_name: &str) -> Result<Response, Error> {
    let mut bereq = Request::new(req.get_method().clone(), req.get_url_str());
    
    bereq.set_version(req.get_version());
    
    for (name, value) in req.get_headers() {
        bereq.set_header(name, value);
    }
    
    if let Some(body) = req.take_body() {
        bereq.set_body(body);
    }
    
    let mut beresp = bereq.send(backend_name)?;
    
    let mut resp = Response::new();
    resp.set_status(beresp.get_status());
    resp.set_version(beresp.get_version());
    
    for (name, value) in beresp.get_headers() {
        resp.set_header(name, value);
    }
    
    if let Some(body) = beresp.take_body() {
        resp.set_body(body);
    }
    
    Ok(resp)
}